;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@se f=kacha
@changefloor pimg=&'game.map.getFloorInfo().pimg == "candle" ? "lighten" : "candle"'
[eventoff cond='game.map.getFloorInfo(4, 8).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(5, 8).pimg != "lighten"']
[eventoff cond='game.map.getFloorInfo(6, 8).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 7).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(3, 7).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(7, 7).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(8, 7).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 6).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 5).pimg != "lighten"']
[eventoff cond='game.map.getFloorInfo(2, 4).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 3).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 2).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(8, 6).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(8, 4).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(8, 3).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(8, 2).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(2, 1).pimg != "candle"']
[eventoff cond='game.map.getFloorInfo(3, 1).pimg != "lighten"']
[eventoff cond='game.map.getFloorInfo(7, 1).pimg != "lighten"']
[eventoff cond='game.map.getFloorInfo(8, 1).pimg != "candle"']
@delevent
@wait time=800
@se f=fence
@switchfence x=5 y=1 way=s mode=open
@notice text="I heard a door open somewhere!"

[eventoff]
